"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[2402],{45077(n,t,r){r.r(t),r.d(t,{assets:()=>o,contentTitle:()=>a,default:()=>u,frontMatter:()=>d,metadata:()=>e,toc:()=>i});const e=JSON.parse('{"id":"cpp23/stacktrace","title":"std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09","description":"C++23 std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09 \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp23/61-stacktrace.md","sourceDirName":"cpp23","slug":"/cpp23/61-stacktrace","permalink":"/LearnModernCpp/docs/cpp23/61-stacktrace","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp23","permalink":"/LearnModernCpp/docs/tags/cpp-23"},{"inline":true,"label":"stacktrace","permalink":"/LearnModernCpp/docs/tags/stacktrace"}],"version":"current","sidebarPosition":62,"frontMatter":{"sidebar_position":62,"slug":"61-stacktrace","title":"std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09","description":"C++23 std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09 \u6559\u5b66\u793a\u4f8b","tags":["cpp23","stacktrace"]},"sidebar":"docs","previous":{"title":"std::unreachable\uff08\u4e0d\u53ef\u8fbe\u6807\u8bb0\uff09","permalink":"/LearnModernCpp/docs/cpp23/44-unreachable"},"next":{"title":"std::byteswap\uff08\u5b57\u8282\u5e8f\u8f6c\u6362\uff09","permalink":"/LearnModernCpp/docs/cpp23/70-byteswap"}}');var s=r(74848),c=r(28453);const d={sidebar_position:62,slug:"61-stacktrace",title:"std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09",description:"C++23 std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09 \u6559\u5b66\u793a\u4f8b",tags:["cpp23","stacktrace"]},a="std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09",o={},i=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,c.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"stdstacktrace\u6808\u8ffd\u8e2a",children:"std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09"})}),"\n",(0,s.jsx)(t.p,{children:"C++23 \u6807\u51c6\u5f15\u5165\u7684 std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09 \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp23/61_stacktrace.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09\r\n * \u6240\u5c5e\u6807\u51c6: C++23\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::stacktrace \u63d0\u4f9b\u4e86\u5728\u8fd0\u884c\u65f6\u83b7\u53d6\u5f53\u524d\u8c03\u7528\u6808\u4fe1\u606f\u7684\r\n *          \u6807\u51c6\u65b9\u5f0f\u3002\u5b83\u53ef\u4ee5\u6355\u83b7\u51fd\u6570\u8c03\u7528\u94fe\uff0c\u7528\u4e8e\u9519\u8bef\u8bca\u65ad\u3001\u65e5\u5fd7\r\n *          \u8bb0\u5f55\u7b49\u573a\u666f\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u5728 C++23 \u4e4b\u524d\uff0c\u83b7\u53d6\u6808\u8ffd\u8e2a\u4fe1\u606f\u9700\u8981\u4f9d\u8d56\u5e73\u53f0\u7279\u5b9a\r\n *              API\uff08\u5982 Linux \u7684 backtrace()\u3001Windows \u7684\r\n *              CaptureStackBackTrace()\uff09\u6216\u7b2c\u4e09\u65b9\u5e93\uff08\u5982 Boost.\r\n *              Stacktrace\uff09\u3002\u6807\u51c6\u5316\u4f7f\u5f97\u8de8\u5e73\u53f0\u6808\u8ffd\u8e2a\u6210\u4e3a\u53ef\u80fd\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - std::stacktrace::current() \u83b7\u53d6\u5f53\u524d\u6808\u8ffd\u8e2a\r\n *   - std::stacktrace_entry \u8868\u793a\u6808\u4e2d\u7684\u5355\u4e2a\u5e27\r\n *   - \u53ef\u4ee5\u83b7\u53d6\u6587\u4ef6\u540d\u3001\u884c\u53f7\u3001\u51fd\u6570\u540d\u7b49\u4fe1\u606f\r\n *   - \u9700\u8981 <stacktrace> \u5934\u6587\u4ef6\r\n *   - \u6ce8\u610f\uff1a\u8bb8\u591a\u7f16\u8bd1\u5668\u5bf9\u6b64\u7279\u6027\u7684\u652f\u6301\u4ecd\u4e0d\u5b8c\u6574\r\n *   - \u53ef\u80fd\u9700\u8981\u94fe\u63a5\u989d\u5916\u7684\u5e93\uff08\u5982 -lstdc++_libbacktrace\uff09\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <sstream>\r\n\r\n// ============================================================\r\n// \u7279\u6027\u68c0\u6d4b\r\n// ============================================================\r\n#if __has_include(<stacktrace>)\r\n#include <stacktrace>\r\n#ifdef __cpp_lib_stacktrace\r\n#define HAS_STACKTRACE 1\r\n#else\r\n#define HAS_STACKTRACE 0\r\n#endif\r\n#else\r\n#define HAS_STACKTRACE 0\r\n#endif\r\n\r\n#if HAS_STACKTRACE\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nnamespace basic_usage {\r\n\r\nvoid inner_function() {\r\n    std::cout << "  -- \u5728 inner_function \u4e2d\u83b7\u53d6\u6808\u8ffd\u8e2a --" << std::endl;\r\n    auto trace = std::stacktrace::current();\r\n\r\n    std::cout << "  \u6808\u6df1\u5ea6: " << trace.size() << " \u5e27" << std::endl;\r\n    std::cout << "  \u6808\u8ffd\u8e2a:" << std::endl;\r\n    for (std::size_t i = 0; i < trace.size() && i < 10; ++i) {\r\n        const auto& entry = trace[i];\r\n        std::cout << "    [" << i << "] " << entry.description();\r\n        if (!entry.source_file().empty()) {\r\n            std::cout << " (" << entry.source_file()\r\n                      << ":" << entry.source_line() << ")";\r\n        }\r\n        std::cout << std::endl;\r\n    }\r\n    if (trace.size() > 10) {\r\n        std::cout << "    ... (\u7701\u7565\u4e86 " << trace.size() - 10 << " \u5e27)" << std::endl;\r\n    }\r\n}\r\n\r\nvoid middle_function() {\r\n    inner_function();\r\n}\r\n\r\nvoid outer_function() {\r\n    middle_function();\r\n}\r\n\r\nvoid demonstrate() {\r\n    std::cout << "[\u57fa\u7840\u7528\u6cd5]" << std::endl;\r\n\r\n    // \u7b80\u5355\u83b7\u53d6\u6808\u8ffd\u8e2a\r\n    std::cout << "  -- \u57fa\u672c\u6808\u8ffd\u8e2a --" << std::endl;\r\n    auto trace = std::stacktrace::current();\r\n    std::cout << "  \u5f53\u524d\u6808\u8ffd\u8e2a:" << std::endl;\r\n    std::cout << trace << std::endl;\r\n\r\n    // \u901a\u8fc7\u8c03\u7528\u94fe\u83b7\u53d6\r\n    std::cout << "  -- \u591a\u5c42\u8c03\u7528\u6808 --" << std::endl;\r\n    outer_function();\r\n\r\n    std::cout << std::endl;\r\n}\r\n\r\n} // namespace basic_usage\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\nnamespace advanced_usage {\r\n\r\n// \u5e26\u6808\u8ffd\u8e2a\u7684\u5f02\u5e38\u7c7b\r\nclass TracedException : public std::exception {\r\npublic:\r\n    TracedException(const std::string& msg)\r\n        : message_(msg)\r\n        , trace_(std::stacktrace::current()) {}\r\n\r\n    const char* what() const noexcept override {\r\n        return message_.c_str();\r\n    }\r\n\r\n    const std::stacktrace& trace() const noexcept {\r\n        return trace_;\r\n    }\r\n\r\n    std::string full_report() const {\r\n        std::ostringstream oss;\r\n        oss << "\u5f02\u5e38: " << message_ << "\\n";\r\n        oss << "\u6808\u8ffd\u8e2a:\\n" << trace_;\r\n        return oss.str();\r\n    }\r\n\r\nprivate:\r\n    std::string message_;\r\n    std::stacktrace trace_;\r\n};\r\n\r\nvoid problematic_function(int x) {\r\n    if (x < 0) {\r\n        throw TracedException("\u53c2\u6570\u4e0d\u80fd\u4e3a\u8d1f\u6570: " + std::to_string(x));\r\n    }\r\n}\r\n\r\nvoid caller_function(int x) {\r\n    problematic_function(x);\r\n}\r\n\r\n// \u65e5\u5fd7\u8f85\u52a9\u51fd\u6570\r\nvoid log_with_trace(const std::string& level, const std::string& msg) {\r\n    auto trace = std::stacktrace::current();\r\n    std::cout << "  [" << level << "] " << msg << std::endl;\r\n    if (trace.size() > 1) {\r\n        // \u8df3\u8fc7 log_with_trace \u81ea\u8eab\r\n        std::cout << "    \u8c03\u7528\u4f4d\u7f6e: " << trace[1].description() << std::endl;\r\n    }\r\n}\r\n\r\nvoid demonstrate() {\r\n    std::cout << "[\u8fdb\u9636\u7528\u6cd5]" << std::endl;\r\n\r\n    // \u573a\u666f1\uff1a\u5e26\u6808\u8ffd\u8e2a\u7684\u5f02\u5e38\r\n    std::cout << "  -- \u5e26\u6808\u8ffd\u8e2a\u7684\u5f02\u5e38 --" << std::endl;\r\n    try {\r\n        caller_function(-5);\r\n    } catch (const TracedException& e) {\r\n        std::cout << e.full_report() << std::endl;\r\n    }\r\n\r\n    // \u573a\u666f2\uff1a\u65e5\u5fd7\u4e2d\u9644\u5e26\u8c03\u7528\u4f4d\u7f6e\r\n    std::cout << "  -- \u65e5\u5fd7\u9644\u5e26\u8c03\u7528\u4f4d\u7f6e --" << std::endl;\r\n    log_with_trace("INFO", "\u7cfb\u7edf\u542f\u52a8\u5b8c\u6210");\r\n    log_with_trace("WARNING", "\u5185\u5b58\u4f7f\u7528\u7387\u8f83\u9ad8");\r\n\r\n    // \u573a\u666f3\uff1a\u6808\u5e27\u7684\u8be6\u7ec6\u4fe1\u606f\r\n    std::cout << "  -- \u6808\u5e27\u8be6\u7ec6\u4fe1\u606f --" << std::endl;\r\n    auto trace = std::stacktrace::current();\r\n    if (!trace.empty()) {\r\n        const auto& entry = trace[0];\r\n        std::cout << "  \u63cf\u8ff0: " << entry.description() << std::endl;\r\n        std::cout << "  \u6e90\u6587\u4ef6: " << entry.source_file() << std::endl;\r\n        std::cout << "  \u884c\u53f7: " << entry.source_line() << std::endl;\r\n    }\r\n\r\n    std::cout << std::endl;\r\n}\r\n\r\n} // namespace advanced_usage\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nnamespace pitfalls {\r\n\r\nvoid demonstrate() {\r\n    std::cout << "[\u6613\u9519\u70b9\u4e0e\u9677\u9631]" << std::endl;\r\n\r\n    // \u9677\u96311\uff1a\u6027\u80fd\u5f00\u9500\r\n    std::cout << "  \u9677\u96311: \u83b7\u53d6\u6808\u8ffd\u8e2a\u6709\u663e\u8457\u6027\u80fd\u5f00\u9500" << std::endl;\r\n    std::cout << "    - \u4e0d\u8981\u5728\u6027\u80fd\u5173\u952e\u8def\u5f84\u4e2d\u4f7f\u7528" << std::endl;\r\n    std::cout << "    - \u9002\u5408\u7528\u4e8e\u9519\u8bef\u5904\u7406\u3001\u65e5\u5fd7\u7b49\u4f4e\u9891\u573a\u666f" << std::endl;\r\n\r\n    // \u9677\u96312\uff1a\u7f16\u8bd1\u5668\u652f\u6301\u4e0d\u5b8c\u6574\r\n    std::cout << "  \u9677\u96312: \u7f16\u8bd1\u5668\u652f\u6301\u72b6\u6001" << std::endl;\r\n    std::cout << "    - GCC: \u9700\u8981 -lstdc++_libbacktrace \u94fe\u63a5" << std::endl;\r\n    std::cout << "    - MSVC: \u652f\u6301\u8f83\u597d" << std::endl;\r\n    std::cout << "    - Clang: \u652f\u6301\u53ef\u80fd\u4e0d\u5b8c\u6574" << std::endl;\r\n\r\n    // \u9677\u96313\uff1a\u4f18\u5316\u7ea7\u522b\u5f71\u54cd\r\n    std::cout << "  \u9677\u96313: \u4f18\u5316\u7ea7\u522b\u5f71\u54cd\u6808\u8ffd\u8e2a\u8d28\u91cf" << std::endl;\r\n    std::cout << "    - -O0: \u4fe1\u606f\u6700\u5b8c\u6574" << std::endl;\r\n    std::cout << "    - -O2/-O3: \u5185\u8054\u7b49\u4f18\u5316\u53ef\u80fd\u5bfc\u81f4\u5e27\u7f3a\u5931" << std::endl;\r\n    std::cout << "    - \u5efa\u8bae: \u5e26\u8c03\u8bd5\u4fe1\u606f\u7f16\u8bd1 (-g)" << std::endl;\r\n\r\n    // \u9677\u96314\uff1a\u7ebf\u7a0b\u5b89\u5168\r\n    std::cout << "  \u9677\u96314: stacktrace::current() \u6355\u83b7\u8c03\u7528\u7ebf\u7a0b\u7684\u6808" << std::endl;\r\n    std::cout << "    - \u6bcf\u4e2a\u7ebf\u7a0b\u6709\u81ea\u5df1\u7684\u8c03\u7528\u6808" << std::endl;\r\n    std::cout << "    - \u4e0d\u80fd\u83b7\u53d6\u5176\u4ed6\u7ebf\u7a0b\u7684\u6808\u8ffd\u8e2a" << std::endl;\r\n\r\n    std::cout << std::endl;\r\n}\r\n\r\n} // namespace pitfalls\r\n\r\n#endif // HAS_STACKTRACE\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09 - C++23 =====\\n" << std::endl;\r\n\r\n#if HAS_STACKTRACE\r\n    basic_usage::demonstrate();\r\n    advanced_usage::demonstrate();\r\n    pitfalls::demonstrate();\r\n#else\r\n    std::cout << "[\u63d0\u793a] \u5f53\u524d\u7f16\u8bd1\u5668\u4e0d\u652f\u6301 std::stacktrace \u7279\u6027\u3002" << std::endl;\r\n    std::cout << "\u8fd9\u662f C++23 \u4e2d\u652f\u6301\u6700\u4e0d\u5b8c\u6574\u7684\u7279\u6027\u4e4b\u4e00\u3002" << std::endl;\r\n    std::cout << std::endl;\r\n    std::cout << "\u7f16\u8bd1\u5668\u652f\u6301\u60c5\u51b5\uff1a" << std::endl;\r\n    std::cout << "  - GCC 14+: \u9700\u8981\u94fe\u63a5 -lstdc++_libbacktrace" << std::endl;\r\n    std::cout << "  - MSVC 19.34+: \u8f83\u597d\u652f\u6301" << std::endl;\r\n    std::cout << "  - Clang: \u652f\u6301\u53ef\u80fd\u4e0d\u5b8c\u6574" << std::endl;\r\n    std::cout << std::endl;\r\n    std::cout << "std::stacktrace \u8bed\u6cd5\u793a\u4f8b\uff08\u4f9b\u53c2\u8003\uff09\uff1a" << std::endl;\r\n    std::cout << R"(\r\n    #include <stacktrace>\r\n    #include <iostream>\r\n\r\n    void debug_function() {\r\n        // \u83b7\u53d6\u5f53\u524d\u6808\u8ffd\u8e2a\r\n        auto trace = std::stacktrace::current();\r\n\r\n        // \u6253\u5370\u6574\u4e2a\u6808\u8ffd\u8e2a\r\n        std::cout << trace << std::endl;\r\n\r\n        // \u904d\u5386\u6bcf\u4e00\u5e27\r\n        for (const auto& entry : trace) {\r\n            std::cout << entry.description() << std::endl;\r\n            std::cout << "  \u6587\u4ef6: " << entry.source_file() << std::endl;\r\n            std::cout << "  \u884c\u53f7: " << entry.source_line() << std::endl;\r\n        }\r\n    }\r\n\r\n    // \u5e26\u6808\u8ffd\u8e2a\u7684\u5f02\u5e38\r\n    class MyException : public std::exception {\r\n        std::string msg_;\r\n        std::stacktrace trace_;\r\n    public:\r\n        MyException(const std::string& msg)\r\n            : msg_(msg), trace_(std::stacktrace::current()) {}\r\n        const char* what() const noexcept override { return msg_.c_str(); }\r\n        const std::stacktrace& trace() const { return trace_; }\r\n    };\r\n)" << std::endl;\r\n\r\n    // \u5e73\u53f0\u7279\u5b9a\u7684\u66ff\u4ee3\u65b9\u6848\r\n    std::cout << "\u5e73\u53f0\u7279\u5b9a\u66ff\u4ee3\u65b9\u6848\uff1a" << std::endl;\r\n#if defined(__GNUC__) || defined(__clang__)\r\n    std::cout << "  \u5f53\u524d\u5e73\u53f0 (GCC/Clang): \u53ef\u4f7f\u7528 <execinfo.h> \u7684 backtrace()" << std::endl;\r\n#elif defined(_MSC_VER)\r\n    std::cout << "  \u5f53\u524d\u5e73\u53f0 (MSVC): \u53ef\u4f7f\u7528 CaptureStackBackTrace()" << std::endl;\r\n#endif\r\n    std::cout << "  \u8de8\u5e73\u53f0\u5e93: Boost.Stacktrace, backward-cpp" << std::endl;\r\n#endif\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/utility/basic_stacktrace",children:"cppreference: std::stacktrace\uff08\u6808\u8ffd\u8e2a\uff09"})}),"\n"]})]})}function u(n={}){const{wrapper:t}={...(0,c.R)(),...n.components};return t?(0,s.jsx)(t,{...n,children:(0,s.jsx)(l,{...n})}):l(n)}},28453(n,t,r){r.d(t,{R:()=>d,x:()=>a});var e=r(96540);const s={},c=e.createContext(s);function d(n){const t=e.useContext(c);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function a(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:d(n.components),e.createElement(c.Provider,{value:t},n.children)}}}]);